// db.js
require('dotenv').config();
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.PGUSER,
  host: process.env.PGHOST,
  database: process.env.PGDATABASE,
  password: process.env.PGPASSWORD,
  port: process.env.PGPORT,
});

pool.on('error', (err, client) => {
  console.error('Unexpected error on idle client', err);
  process.exit(-1);
});

module.exports = {
  query: (text, params) => pool.query(text, params),
  getClient: () => pool.connect(),
};

// models/product.js
const db = require('../db');

const Product = {
  async create({ name, description, price, category_id }) {
    const result = await db.query(
      'INSERT INTO products (name, description, price, category_id) VALUES ($1, $2, $3, $4) RETURNING *',
      [name, description, price, category_id]
    );
    return result.rows[0];
  },

  async findAll() {
    const result = await db.query(
      'SELECT p.*, c.name AS category_name FROM products p LEFT JOIN categories c ON p.category_id = c.id ORDER BY p.id ASC'
    );
    return result.rows;
  },

  async findById(id) {
    const result = await db.query(
      'SELECT p.*, c.name AS category_name FROM products p LEFT JOIN categories c ON p.category_id = c.id WHERE p.id = $1',
      [id]
    );
    return result.rows[0];
  },

  async update(id, { name, description, price, category_id }) {
    const result = await db.query(
      'UPDATE products SET name = $1, description = $2, price = $3, category_id = $4, updated_at = CURRENT_TIMESTAMP WHERE id = $5 RETURNING *',
      [name, description, price, category_id, id]
    );
    return result.rows[0];
  },

  async delete(id) {
    const result = await db.query('DELETE FROM products WHERE id = $1 RETURNING *', [id]);
    return result.rows[0];
  },
};

module.exports = Product;

// models/category.js
const db = require('../db');

const Category = {
  async create({ name }) {
    const result = await db.query(
      'INSERT INTO categories (name) VALUES ($1) RETURNING *',
      [name]
    );
    return result.rows[0];
  },

  async findAll() {
    const result = await db.query('SELECT * FROM categories ORDER BY id ASC');
    return result.rows;
  },

  async findById(id) {
    const result = await db.query('SELECT * FROM categories WHERE id = $1', [id]);
    return result.rows[0];
  },

  async update(id, { name }) {
    const result = await db.query(
      'UPDATE categories SET name = $1 WHERE id = $2 RETURNING *',
      [name, id]
    );
    return result.rows[0];
  },

  async delete(id) {
    // Note: Products referencing this category will have category_id set to NULL due to ON DELETE SET NULL
    const result = await db.query('DELETE FROM categories WHERE id = $1 RETURNING *', [id]);
    return result.rows[0];
  },
};

module.exports = Category;

// routes/products.js
const express = require('express');
const Product = require('../models/product');
const router = express.Router();

// Get all products
router.get('/', async (req, res) => {
  try {
    const products = await Product.findAll();
    res.json(products);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Get product by ID
router.get('/:id', async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product) {
      return res.status(404).json({ msg: 'Product not found' });
    }
    res.json(product);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Create a new product
router.post('/', async (req, res) => {
  try {
    const newProduct = await Product.create(req.body);
    res.status(201).json(newProduct);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Update a product
router.put('/:id', async (req, res) => {
  try {
    const updatedProduct = await Product.update(req.params.id, req.body);
    if (!updatedProduct) {
      return res.status(404).json({ msg: 'Product not found' });
    }
    res.json(updatedProduct);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Delete a product
router.delete('/:id', async (req, res) => {
  try {
    const deletedProduct = await Product.delete(req.params.id);
    if (!deletedProduct) {
      return res.status(404).json({ msg: 'Product not found' });
    }
    res.json({ msg: 'Product deleted', product: deletedProduct });
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

module.exports = router;

// routes/categories.js
const express = require('express');
const Category = require('../models/category');
const router = express.Router();

// Get all categories
router.get('/', async (req, res) => {
  try {
    const categories = await Category.findAll();
    res.json(categories);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Get category by ID
router.get('/:id', async (req, res) => {
  try {
    const category = await Category.findById(req.params.id);
    if (!category) {
      return res.status(404).json({ msg: 'Category not found' });
    }
    res.json(category);
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

// Create a new category
router.post('/', async (req, res) => {
  try {
    const newCategory = await Category.create(req.body);
    res.status(201).json(newCategory);
  } catch (err) {
    console.error(err.message);
    // Handle unique constraint error specifically
    if (err.code === '23505') { // PostgreSQL unique violation error code
      return res.status(409).json({ msg: 'Category with this name already exists' });
    }
    res.status(500).send('Server Error');
  }
});

// Update a category
router.put('/:id', async (req, res) => {
  try {
    const updatedCategory = await Category.update(req.params.id, req.body);
    if (!updatedCategory) {
      return res.status(404).json({ msg: 'Category not found' });
    }
    res.json(updatedCategory);
  } catch (err) {
    console.error(err.message);
    if (err.code === '23505') {
      return res.status(409).json({ msg: 'Category with this name already exists' });
    }
    res.status(500).send('Server Error');
  }
});

// Delete a category
router.delete('/:id', async (req, res) => {
  try {
    const deletedCategory = await Category.delete(req.params.id);
    if (!deletedCategory) {
      return res.status(404).json({ msg: 'Category not found' });
    }
    res.json({ msg: 'Category deleted', category: deletedCategory });
  } catch (err) {
    console.error(err.message);
    res.status(500).send('Server Error');
  }
});

module.exports = router;

// server.js
require('dotenv').config();
const express = require('express');
const productRoutes = require('./routes/products');
const categoryRoutes = require('./routes/categories');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// Root route
app.get('/', (req, res) => {
  res.send('Welcome to the Node.js PostgreSQL CRUD API!');
});

// Use API routes
app.use('/api/products', productRoutes);
app.use('/api/categories', categoryRoutes);

// Start the server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});